"""
MKT Original Commentary — Jeremiah chapters 14–17
Run: python3 scripts/zc-original-jeremiah-14-17.py

Key translation decisions:
- 14:8: miqweh Yisrael = "hope of Israel" — same root as cistern/water, wordplay with drought
- 14:14: sheqer hinnabeim = "prophesying falsehoods" — lit. "lying prophesying"
- 15:1: Moses and Samuel — the two supreme OT intercessors; YHWH's refusal is absolute
- 15:16: "I devoured your words" — the Ezekiel 3 parallel; eating the divine scroll
- 15:18: akhzav = "deceptive stream" — the wadi that dries up; daring language for YHWH
- 15:19: tshuv / ashivkha — the double-shub verb; return-and-restore
- 16:14-15: new exodus oracle — the second exodus surpasses the Exodus from Egypt
- 16:19: nations come to YHWH from the ends of the earth
- 17:1: written with iron stylus on the heart tablet
- 17:5-8: cursed/blessed antithesis — parallel to Psalm 1
- 17:9: aqov hallev — "more deceitful than anything" / "desperately sick"
- 17:10: YHWH examines heart and tests inner mind (kelayot = kidneys/inner self)
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    return json.loads(p.read_text()) if p.exists() else {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

JEREMIAH = {
"14": {
"1": "<p>The superscription <em>ʾăšer hāyâ dĕbar YHWH ʾel-Yirmĕyāhû ʿal-dibrê habbaṣṣārôt</em> — &quot;the word that came to Jeremiah concerning the drought(s)&quot;; <em>baṣṣārôt</em> (plural of <em>baṣṣōret</em>) denotes droughts or famines — the plural may suggest multiple drought events. The MKT renders &quot;the word that came to Jeremiah from the LORD concerning the drought&quot; treating the plural as a collective.</p>",
"2": "<p><strong>ʾābĕlâ Yĕhûdâ</strong> — &quot;Judah mourns&quot;; <em>ʾābal</em> is the verb for formal mourning, used of communities in distress. &quot;City gates droop in gloom&quot; (<em>šaʿărêhā ʾumĕlālû</em>): <em>ʾāmal</em> means to languish, droop. The personification of the gates as mourners makes the whole city a unified mourning body. The MKT follows the MT&apos;s striking personification rather than flattening it.</p>",
"3": "<p>The social structure of the drought revealed: officials (<em>ʾaddîrêhem</em>, the great ones) send servants (<em>ṣĕʿîrêhem</em>, the lesser ones) to cisterns that are empty. The shame gesture &quot;cover their heads&quot; (<em>ḥāpû rōʾšām</em>) indicates grief or humiliation. All social levels are equally helpless before the covenant curse of drought.</p>",
"4": "<p><strong>kî lōʾ hāyâ gešem</strong> — &quot;because there has been no rain&quot;; the explicit causal statement of the drought. The farmers &quot;cover their heads&quot; in the same gesture as the servants in v.3 — the drought levels social distinctions in shared despair. <em>ʿAdāmâ ḥattâ</em> (the ground is cracked/dismayed) — the same verb <em>ḥātat</em> used for human dismay applies to the land.</p>",
"5": "<p>The natural world used as evidence: even the nursing doe (<em>ʾayyālâ baśśādeh</em>, doe in the field) abandons her newborn (<em>nāṭĕšâ</em> = abandoned, forsaken) because there is no grass. Animals do not abandon their young except under extreme conditions — the drought is so severe it overrides maternal instinct. The MKT preserves the emotional force of this image.</p>",
"6": "<p><strong>pĕrāʾîm ʿāmdû ʿal-šĕpāyim</strong> — &quot;the wild donkeys stand on the barren ridges&quot;; wild donkeys were known for their sharp eyes and ability to find water; now they gasp for air like jackals (<em>šāʾăpû rûaḥ kattannîm</em>). &quot;Their eyes grow dim&quot; (<em>kālû ʿênêhem</em>) — the failure of keen eyesight signals total ecological collapse.</p>",
"7": "<p><strong>ʿăśēh lĕmaʿan šĕmekā</strong> — &quot;act for the sake of your name&quot;; the appeal to YHWH&apos;s own reputation grounds Israel&apos;s lament. <em>Mĕšûbôtênû rabbû lĕkā ḥāṭāʾnû</em> — &quot;our unfaithfulness is many times over; we have sinned against you.&quot; The confession is corporate and unqualified. The MKT preserves the name-appeal as the primary petitionary basis distinct from Israel&apos;s merit.</p>",
"8": "<p><strong>miqweh Yiśrāʾēl</strong> — &quot;O hope of Israel&quot;; <em>miqweh</em> means both hope and a pool/reservoir of water — a deliberate wordplay in the drought context. YHWH is Israel&apos;s true water-source while the cisterns are empty. &quot;Like a foreigner in the land, like a traveler who stops only for the night&quot; — the accusation that YHWH has become a transient, not a permanent dweller. The MKT preserves the &quot;hope&quot; rendering but the water-pun enriches it for readers aware of the drought context.</p>",
"9": "<p><strong>kĕgibbôr lōʾ-yûkal lĕhôšîaʿ</strong> — &quot;like a warrior who is powerless to save&quot;; the bold challenge questioning YHWH&apos;s power. The prayer then recovers: &quot;You are still in the midst of us, LORD, and we bear your name.&quot; The tension between accusation and reaffirmation is characteristic of biblical lament. The MKT preserves &quot;in the midst of us&quot; (<em>bĕqirbēnû</em>) as the ground for the continued plea.</p>",
"10": "<p>YHWH&apos;s response refuses the lament: &quot;They have loved to wander&quot; (<em>ʾāhăbû lānûaʿ</em>) — their wandering after idols is a chosen lifestyle, not an involuntary drift. <em>Lōʾ-ḥāśĕkû ragĕlêhem</em> — &quot;they have not restrained their feet.&quot; The MKT&apos;s &quot;loved to wander&quot; preserves the volitional dimension — this is desire, not weakness.</p>",
"11": "<p>YHWH&apos;s second prohibition of intercession (cf. 7:16): <em>ʾal-titpallēl bĕʿad hāʿām hazzeh lĕṭôbâ</em> — &quot;Do not pray for the welfare of this people.&quot; The phrase <em>lĕṭôbâ</em> (for good/welfare) specifies what is being forbidden — not all prayer, but petitions for blessing. The judgment is now irreversible; intercession would only oppose YHWH&apos;s just decree.</p>",
"12": "<p>The three channels of approach to YHWH — fasting (<em>ṣûm</em>), burnt offerings (<em>ʿōlâ</em>), and grain offerings (<em>minḥâ</em>) — will all be ignored. The covenant&apos;s normal means of approach are suspended. The MKT preserves all three ritual forms to show the comprehensiveness of the suspension: no ritual avenue remains open.</p>",
"13": "<p>Jeremiah&apos;s objection: the false prophets are promising peace and security — the people are being misled, not simply disobeying. <em>Ḥereb lōʾ-tirʾû ... šālôm ʾĕmet ʾettēn lākem</em> — &quot;You will not face war... I will give you lasting peace.&quot; The word <em>ʾĕmet</em> (truth, reliability) placed in the false prophets&apos; mouths is particularly ironic — they claim their peace is the real/true peace.</p>",
"14": "<p><strong>šeqer hanněbîʾîm nibbāʾîm</strong> — &quot;The prophets are prophesying falsehoods (<em>šeqer</em>) in my name&quot;; three parallel divine disavowals: &quot;I did not send them (<em>lōʾ šĕlaḥtîm</em>), I did not command them (<em>wĕlōʾ ṣiwwîtîm</em>), and I did not speak to them (<em>wĕlōʾ dibbartî ʾălêhem</em>).&quot; The triple negation is emphatic. The MKT preserves all three verbs of sending/commanding/speaking.</p>",
"15": "<p>The judgment on the false prophets mirrors what they falsely promised: they promised no sword or famine; they will die by sword and famine. The poetic justice of this reversal is intentional — the prophets who denied the covenant curses will personally experience them. The MKT preserves the verbal echo: same terms (<em>ḥereb</em> and <em>rāʿāb</em>) in judgment that were denied in their oracles.</p>",
"16": "<p>The people who trusted the false prophets are thrown into the streets — the reverse of the temple-court security they were promised. <em>Wĕhišpaktî ʿălêhem ʾet-rāʿātām</em> — &quot;I will pour out their wickedness upon them&quot;; the judgment is a pouring-out that mirrors the rain withheld in the drought. The MKT&apos;s &quot;pour out&quot; preserves this ironic contrast.</p>",
"17": "<p><strong>tērdanâ ʿênî dimʿâ laylâ wĕyômām</strong> — &quot;Let my eyes overflow with tears night and day without stopping&quot;; YHWH (or the prophet) commanded to weep. The phrase <em>ʾal-tiddōm</em> (without stopping, without ceasing) intensifies the mourning to uninterrupted grief. &quot;The virgin daughter of my people&quot; (<em>bat-ʿammî</em>) — a personification of the nation as a young woman struck down.</p>",
"18": "<p><strong>ûbāʾû ʾel-ʾereṣ</strong> — &quot;Both prophet and priest have gone to a land they do not know&quot;; the religious leaders are already going into exile before the final judgment. The verse is difficult: the MKT renders &quot;both the prophet and the priest ply their trade in a land they do not know&quot; — possibly meaning they practice their false trade even in exile. The uncertainty of this verse is acknowledged in the MKT rendering.</p>",
"19": "<p><strong>hāmāʾōs māʾasta ʾet-Yĕhûdâ</strong> — &quot;Have you completely rejected Judah?&quot; — the infinitive absolute (<em>māʾōs māʾasta</em>, &quot;in rejecting have you rejected&quot;) conveys absolute rejection. &quot;Does your very being recoil from Zion?&quot; (<em>bĕṣiyyôn gāʿălâ napšekā</em>) — <em>gāʿal</em> means to loathe/abhor; the question dares to say YHWH&apos;s <em>nepeš</em> (inner self/being) is revolted by Zion.</p>",
"20": "<p><strong>yādaʿnû YHWH rišʿēnû</strong> — &quot;We acknowledge, O LORD, our own wickedness&quot;; the corporate confession moves from questioning (v.19) to acknowledgment. The dual confession: our own wickedness (<em>rišʿēnû</em>) and our ancestors&apos; sins (<em>ʿăwōn ʾăbôtênû</em>). The MKT preserves both the first-person and ancestral dimensions of the confession.</p>",
"21": "<p><strong>lĕmaʿan šĕmekā</strong> — &quot;for the sake of your name&quot;; the dual appeal of v.21: name (<em>šēm</em>) and covenant (<em>bĕrît</em>). &quot;Do not dishonor the throne of your glory&quot; (<em>kissēʾ kĕbôdekā</em>) — the temple as YHWH&apos;s earthly throne is implicated in Israel&apos;s fate; its destruction would dishonor YHWH. The MKT preserves this implicit argument: YHWH&apos;s honor is at stake in Israel&apos;s survival.</p>",
"22": "<p><strong>hăyēš bahabrê haggôyim mağšîmîm</strong> — &quot;Are there any among the idols of the nations that can make it rain?&quot; The drought context makes the idol-powerlessness argument concrete: can idols control rain? The rhetorical answer is no. <em>Hălōʾ ʾattâ-hûʾ YHWH ʾĕlōhênû</em> — &quot;You are the one, O LORD our God.&quot; The monotheistic confession arises from the crisis of the drought.</p>"
},
"15": {
"1": "<p><strong>Mōšeh ûŠĕmûʾēl</strong> — &quot;Even if Moses and Samuel stood before me, my heart would not be moved&quot;; Moses (Exod 32:11-14, Num 14:13-20) and Samuel (1 Sam 7:5-9) were the two supreme intercessors of Israel&apos;s history. Both had moved YHWH to relent before. The fact that even they are named as insufficient underlines the finality of the judgment. The MKT preserves the comparison because it is theologically essential — no human intercession can reverse this decree.</p>",
"2": "<p><strong>ʾăšer lammāwet lammāwet</strong> — &quot;Those destined for death will fall to death&quot;; the fourfold division — death, sword, famine, captivity — is a comprehensive catalogue of the covenant curses. The rhetorical structure (repetition of the noun: &quot;to death to death, to the sword to the sword&quot;) is an emphatic Hebrew form. The MKT preserves the fourfold categories but renders them as natural English: &quot;death... sword... famine... captivity.&quot;</p>",
"3": "<p><strong>ʾarbaʿ mišpāḥôt</strong> — &quot;four kinds of destroyers&quot;; the four agents are personified as <em>mišpāḥôt</em> (families/clans) of destruction. The MKT renders &quot;four kinds of destroyers&quot; rather than the more literal &quot;four families&quot; because the English idiom &quot;families of destroyers&quot; obscures the point. The progression from sword to dogs to birds to beasts represents the complete destruction and desecration of the dead.</p>",
"4": "<p><strong>Mĕnaššeh ben-Ḥizqiyyāhû</strong> — &quot;because of Manasseh son of Hezekiah&quot;; Manasseh&apos;s reign (2 Kgs 21) was the paradigm of apostasy that even Josiah&apos;s reform could not undo. The phrase &quot;a terrifying sight to all the kingdoms of the earth&quot; (<em>zāʿăwâ lĕkōl mamĕlĕkôt hāʾārets</em>) — the nation becomes a spectacle of divine judgment. The MKT&apos;s &quot;terrifying sight&quot; captures the word <em>zaʿăwâ</em> (horror, trembling).</p>",
"5": "<p><strong>mî-yāḥmōl ʿālayik</strong> — &quot;who will feel sorry for you, O Jerusalem?&quot; The three rhetorical questions (who will have compassion? who will grieve? who will stop?) expect the answer: no one. The compassion vocabulary: <em>yāḥmōl</em> (have compassion), <em>yānûd</em> (show grief/commiserate), <em>yisôl lĕšālôm</em> (ask about your welfare). All three forms of social concern are abandoned because the city had abandoned YHWH.</p>",
"6": "<p><strong>nāṭaštî ʾet-ʾaḥôr</strong> — &quot;you keep going backward&quot;; <em>nāṭaš</em> (go backward, draw back) in the niphal. The MKT renders &quot;you keep going backward&quot; — the progressive tense captures the ongoing nature of the retreat. <em>Wāʾettî yādî ʿālayik wāʾašḥîtēk</em> — YHWH stretching out his hand against Israel is the reversal of the Exodus (where the hand was stretched out for Israel).</p>",
"7": "<p><strong>wāʾezrēm bĕmizreh bĕšaʿărê hāʾārets</strong> — &quot;I will winnow them with a fan in the gateways of the land&quot;; the agricultural winnowing image: chaff separated from grain. <em>Bikkaltî šĕkailtî ʾet-ʿammî</em> — &quot;I will strip them of their children (<em>bānim</em>) and destroy my people&quot;. The double verb (<em>kibbeltu šikiltu</em>) — bereave and destroy — is an intensive pair. The MKT follows MT&apos;s two-verb construction.</p>",
"8": "<p><strong>ʿātsĕmû-lî ʾalmĕnôtāyw mēḥôl yammîm</strong> — &quot;their widows have become more numerous to me than the sand of the sea&quot;; a striking reversal of the Abrahamic promise (Gen 22:17 — descendants as sand). Here it is widows, not descendants, who are countless. &quot;A destroyer at midday&quot; (<em>šōdēd baṣṣāhŏrāyim</em>) — midday attack emphasizes the openness and completeness of the slaughter.</p>",
"9": "<p><strong>ʾummâ šibbĕʿat hāyĕlādîm</strong> — &quot;the mother of seven gasps her last breath&quot;; seven sons was the ideal of complete blessing in the ancient world (cf. Ruth 4:15, 1 Sam 1:8). Her sun going down while it is still midday (<em>bāʾ šimšāh bĕʿōd yômmām</em>) inverts the natural order — blessing reversed mid-life.</p>",
"10": "<p><strong>ʾîš rîb wĕʾîš mādôn</strong> — &quot;a man of contention and strife&quot;; Jeremiah&apos;s first personal lament — the prophet curses his own birth (anticipating ch. 20). The MKT preserves &quot;to the whole world&quot; (<em>lĕkol-hāʾārets</em>): Jeremiah&apos;s birth was a source of contention nationally, not just locally. &quot;I have neither lent nor borrowed&quot; — his financial innocence makes his social ostracism incomprehensible to him.</p>",
"11": "<p><strong>ʾim-lōʾ šĕrîtĕkā lĕṭôb</strong> — &quot;Surely I will set what remains of you free for good purposes&quot;; YHWH&apos;s assurance to Jeremiah in the midst of his lament. The MKT renders &quot;what remains of you&quot; — <em>šĕʾêrîtĕkā</em> suggests a remnant or what remains of Jeremiah&apos;s ministry. The promise that enemies will &quot;appeal to you in the time of disaster&quot; is the reversal of Jeremiah&apos;s current humiliation.</p>",
"12": "<p><strong>hăyĕrōaʿ barzel barzel mitstsāpôn</strong> — &quot;Can iron shatter iron from the north — or even bronze?&quot; A difficult verse; the MKT follows the reading that this refers to Babylon (the iron from the north) being an irresistible force. Some read it as a general proverb; the MKT rendering as a rhetorical question emphasizes the rhetorical force rather than a metaphysical claim.</p>",
"13": "<p><strong>ḥêlĕkā ûʾôtsĕrôtêkā lābaz ʾettēn</strong> — &quot;Your wealth and your treasures I will hand over to plunder — free of charge&quot;; <em>lōʾ bĕmĕḥîr</em> (not for a price) means without any economic benefit to Israel — the wealth simply flows out. The phrase &quot;because of all your sins, throughout all your territory&quot; (<em>bĕkol-ḥaṭṭōʾtêkā ûbĕkol-gĕbûlêkā</em>) is comprehensive in scope.</p>",
"14": "<p><strong>kî ʾēš qĕdaḥat bĕʾappî</strong> — &quot;for a fire has been kindled by my anger, and it will burn against you&quot;; the divine anger as consuming fire — a standard OT metaphor. The exile to &quot;a land you have never known&quot; (<em>ʾĕrets ʾăšer lōʾ-yādaʿtā</em>) is the ultimate disorientation: covenantal relationship depended on knowledge of YHWH and of the land; exile dissolves both.</p>",
"15": "<p><strong>yādaʿtā YHWH zĕkĕrēnî ûpĕqĕdēnî</strong> — &quot;You know, O LORD; remember me and care for me&quot;; the second lament — Jeremiah appeals to YHWH&apos;s omniscience as the ground for attention to his own need. &quot;Do not in your forbearance take me away&quot; (<em>bĕʾerek ʾappĕkā ʾal-tiqqāḥēnî</em>) — the prophet fears that YHWH&apos;s patience with the persecutors may come at the cost of the prophet&apos;s own life.</p>",
"16": "<p><strong>nimsĕʾû dĕbārêkā wāʾōklēm</strong> — &quot;When I found your words, I devoured them&quot;; <em>ʾākal</em> (eat/devour) applied to the divine word; cf. Ezek 2:8-3:3 (Ezekiel literally eats the scroll). The MKT&apos;s &quot;devoured them&quot; preserves the physical urgency — not leisurely reading but consuming the words. &quot;Your word was my joy and the delight of my heart&quot; (<em>śāśôn wĕśimḥat lĕbābî</em>): the word that causes Jeremiah such suffering is simultaneously his deepest joy.</p>",
"17": "<p><strong>lōʾ-yāšabtî bĕsôd-mĕśaḥăqîm</strong> — &quot;I did not sit in the company of those who celebrate&quot;; Jeremiah&apos;s separation from normal social life because of his prophetic call. &quot;I sat alone (<em>bādād</em>) because your hand was on me&quot; — <em>bādād</em> (alone, isolated) is the word used for the isolated leper (Lev 13:46) and for Jerusalem destroyed (Lam 1:1: &quot;How desolate she sits, the city once so full of people&quot;). Prophetic isolation as anticipatory solidarity with the exiled city.</p>",
"18": "<p><strong>lāmâ hāyâ kĕʾēbî nĕtsaḥ ûmakkātî ʾănûšâ</strong> — &quot;Why is my pain unending and my wound incurable?&quot; The daring accusation that follows: &quot;Are you really going to be to me like a deceptive stream, like waters that fail?&quot; (<em>hĕyôt tihyeh lî kĕʾakzāb</em>). <em>ʾAkzāb</em> is a wadi that appears full in winter but dries up in summer — the most pointed image for unreliable presence. The MKT&apos;s &quot;deceptive stream&quot; preserves the shocking accusation that YHWH might be like the failed water-sources of the drought.</p>",
"19": "<p><strong>ʾim-tāšûb wĕʾăšîbĕkā</strong> — &quot;If you return, I will restore you&quot;; the double-<em>šûb</em> construction: Jeremiah&apos;s return (repentance/reorientation) is met by YHWH&apos;s returning him to standing. <em>Lĕpānay taʿămōd</em> — &quot;you will stand before me&quot; — the prophetic standing-before-YHWH is restored. &quot;If you speak what is precious rather than what is worthless&quot; — the prophet&apos;s speech must be reoriented before his commission is recommissioned.</p>",
"20": "<p><strong>lĕḥômâ nĕḥōšet bĕṣûrâ</strong> — &quot;a fortified bronze wall&quot; — YHWH&apos;s recommissioning of Jeremiah as an impregnable wall of bronze. This parallels the original commissioning of 1:18 where he was made &quot;a fortified city, an iron pillar, a bronze wall.&quot; The recommissioning after Jeremiah&apos;s complaint restores him to his original calling with the same protective metaphor.</p>",
"21": "<p><strong>wĕhiṣṣaltîkā miyyad rāʿîm</strong> — &quot;I will deliver you from the power of the wicked&quot;; the final assurance completing the recommissioning. <em>Mikkap ʿārîṣîm ʾepĕddekā</em> — &quot;I will rescue you from the grasp of the ruthless&quot;; <em>ʿārîṣ</em> (ruthless one, violent tyrant) describes Jeremiah&apos;s opponents. The divine rescue is YHWH&apos;s responsibility, not something Jeremiah must earn.</p>"
},
"16": {
"1": "<p>A fresh oracle-introduction: <em>wayĕhî dĕbar-YHWH ʾēlay lēʾmōr</em> — the standard prophetic formula for a new divine word. The MKT follows MT in marking this as a new unit. The commands that follow (celibacy, no mourning, no feasting) are sign-acts, not merely moral instructions.</p>",
"2": "<p><strong>lōʾ-tiqqaḥ lĕkā ʾiššâ</strong> — &quot;You must not marry or have sons or daughters in this place&quot;; celibacy as prophetic sign-act — one of the most unusual divine commands given to an OT prophet. The MKT renders &quot;in this place&quot; (<em>bammāqôm hazzeh</em>) as specifying Jerusalem — marriage and family in a place destined for destruction would be an act of false hope. The celibacy enacts the end of normal life.</p>",
"3": "<p>The reason for the marriage-prohibition stated explicitly: sons and daughters born in this place will die of terrible diseases (<em>bĕmōtê taḥalûʾîm</em>). Their mothers and fathers will also die without the covenant dignities of mourning and burial. The MKT follows MT in listing the deaths of parents alongside children — the sign-act encompasses whole family systems.</p>",
"4": "<p><strong>bĕmōtê taḥalûʾîm</strong> — &quot;diseases&quot; or &quot;terrible diseases&quot;; <em>taḥalûʾ</em> means a sickness or wasting disease. &quot;Like dung on the surface of the ground&quot; (<em>kĕdōmen ʿal-pĕnê hāʾădāmâ</em>) — the covenant curse of unburied dead (Deut 28:26). The MKT preserves the dignity-stripping directness: no mourning, no burial, just corpses as manure.</p>",
"5": "<p><strong>bêt marzēaḥ</strong> — &quot;house of mourning&quot;; <em>marzēaḥ</em> was a formal mourning institution or feast associated with death in the ancient Near East. YHWH withdraws his <em>šālôm</em> (well-being), <em>ḥesed</em> (covenant loyalty), and <em>raḥămîm</em> (compassion) from this generation. The MKT renders all three terms because each represents a different covenantal quality being suspended.</p>",
"6": "<p>The prohibition on the normal mourning rites: no cutting (<em>lōʾ-yissĕrĕṭû</em>) and no shaving one&apos;s head (<em>lōʾ-yiqqārĕḥû</em>) for the dead. These were standard mourning gestures (though the Torah also restricted them, Lev 19:28; 21:5). The MKT follows MT in specifying both rites — the complete social apparatus of mourning is suspended.</p>",
"7": "<p><strong>lōʾ-yiprĕsû lāhem leḥem ʿal-ʾēbel</strong> — &quot;No one will offer food to the mourner to comfort him for the dead&quot;; the breaking of bread with mourners was the social solidarity ritual. &quot;The cup of consolation&quot; (<em>kôs tanaḥûmîm</em>) was a ceremonial cup given to the bereaved. The suspension of both communal mourning customs signals the breakdown of society&apos;s capacity for mutual comfort.</p>",
"8": "<p>The second prohibition: <em>bêt mišteh</em> (house of feasting) is also off-limits. Where v.5 forbids mourning and v.8 forbids feasting, Jeremiah&apos;s entire social existence — from grief to celebration — is withdrawn. This total social isolation enacts the coming desolation when both mourning and feasting will be silenced (see 7:34).</p>",
"9": "<p><strong>mašbît mizzeh-hammāqôm lĕʿênêkem ûbîmêkem</strong> — &quot;I am about to silence in this place — within your own sight and in your own days&quot;; YHWH will silence <em>qôl śāśôn wĕqôl śimḥâ qôl ḥātān wĕqôl kallâ</em> — the bridal-joy four-phrase formula (cf. 7:34; 25:10). The temporal specification &quot;within your own sight and in your own days&quot; means those alive now will witness this.</p>",
"10": "<p>The people&apos;s anticipated question: why has YHWH declared all this disaster? The question uses the covenant-word <em>rāʿâ</em> (evil, disaster) — the people recognize the announcement as disaster but not yet as their fault. The MKT preserves the naive question (&quot;What wrong have we done?&quot;) because it sets up the specific answer in vv. 11-13.</p>",
"11": "<p><strong>taḥat ʾăšer-ʿāzĕbû ʾôtî ʾăbôtêkem</strong> — &quot;Because your ancestors forsook me&quot;; the generational dimension of apostasy — the ancestors&apos; rejection of YHWH. The fourfold description of their idolatry: went after (<em>hālĕkû ʾaḥărê</em>), served (<em>wayyaʿăbdûm</em>), worshipped (<em>wayyištaḥăwû lāhem</em>), forsook (<em>wĕʾōtî ʿāzābû</em>) — four verbs of increasing commitment to idolatry.</p>",
"12": "<p><strong>waʾattem hăraʿōtem laʿăśôt</strong> — &quot;you have done even worse than your ancestors&quot; — the downward spiral of apostasy. &quot;Every one of you follows the stubborn evil of his own heart&quot; (<em>ʾîš ʾaḥărê šĕrîrût libbô hārāʿ</em>): <em>šĕrîrût lēb</em> (stubbornness of heart) is Jeremiah&apos;s diagnostic phrase. The refusal to &quot;listen to me&quot; (<em>lĕbiltî šĕmōaʿ ʾēlay</em>) — the covenant obligation of hearing-obedience abandoned.</p>",
"13": "<p><strong>wĕhêtaltî ʾetkem mēʿal hāʾādāmâ</strong> — &quot;I will cast you out of this land&quot;; <em>hētaltî</em> (hurl, fling) conveys a violent expulsion. &quot;Into a land that neither you nor your ancestors have ever known&quot; — the reversal of the covenant land-gift. &quot;There you may serve other gods day and night&quot; — the bitterly ironic permission: you wanted idols, you can have them in exile without YHWH.</p>",
"14": "<p><strong>ʾim-lōʾ hinnēh yāmîm bāʾîm</strong> — &quot;But days are coming&quot;; the transition from judgment to restoration oracle. The new exodus will supersede the Exodus formula: &quot;as the LORD lives who brought Israel out of Egypt&quot; will be replaced by a new oath formula. The MKT&apos;s &quot;people will no longer say: As the LORD lives who brought Israel out of Egypt&quot; preserves the surprising eclipse of the foundational confession.</p>",
"15": "<p><strong>ʾim-kî ḥay-YHWH ʾăšer heʿĕlâ ʾet-bĕnê Yiśrāʾēl mēʾerets ṣāpôn</strong> — &quot;As the LORD lives who brought Israel back from the land of the north&quot;; the second exodus will define YHWH more than the Egyptian exodus. &quot;From all the countries where he had driven them&quot; (<em>mikkol hāʾărāṣôt ʾăšer hiddîḥam šāmmâ</em>) — the global scatter reversed by a global gather. The MKT preserves the geographical specificity: north and all countries.</p>",
"16": "<p><strong>hinnĕnî šōlēaḥ lĕdayyāgîm rabbîm</strong> — &quot;I am sending for many fishermen&quot; — YHWH as the one who sends agents of judgment. The fishermen and hunters are metaphors for the Babylonian armies and their systematic capture of the exiles. The imagery moves from fishing to hunting: both are thorough — no one escapes a comprehensive catch.</p>",
"17": "<p><strong>kî ʿênay ʿal-kol-darkêhem</strong> — &quot;For my eyes are on all their ways&quot;; the divine omniscience provides the warrant for comprehensive judgment. <em>Lōʾ nistarû minnĕged pānāy</em> — &quot;they are not hidden from my sight&quot; — the absolute transparency of human action before YHWH. <em>Wĕlōʾ niṣpan ʿăwōnām minnĕged ʿênāy</em> — even their guilt (<em>ʿāwōn</em>) is not hidden.</p>",
"18": "<p><strong>ûšillāmtî rīšōnâ mišneh ʿăwōnām wĕḥaṭṭāʾtām</strong> — &quot;First I will repay their guilt and their sin in double measure&quot;; <em>mišneh</em> (double) — the full covenant-justice repayment. &quot;Because they have defiled my land with the lifeless images of their detestable idols&quot; (<em>nigbĕlātêhem</em>) — the land-pollution language frames idolatry as a pollution crime against the covenantal territory.</p>",
"19": "<p><strong>YHWH ʿuzzî ûmāʿuzzî ûmānôsî bĕyôm ṣārâ</strong> — &quot;O LORD, my strength and my fortified refuge in the day of distress&quot;; Jeremiah&apos;s prayer of confidence framed as a future hope. The nations coming from the ends of the earth (<em>ʾaprĕsê-ʾārets</em>) is a vision of universal recognition of YHWH&apos;s supremacy. Their confession: &quot;our ancestors inherited nothing but falsehood&quot; (<em>lōʾ-mōʿîl</em>) — the idols are exposed as useless.</p>",
"20": "<p><strong>hăyaʿăśeh-lô ʾādām ʾĕlōhîm</strong> — &quot;Can a person make gods for himself?&quot; The rhetorical question exposes the absurdity of idol-making. &quot;But they are no gods at all&quot; (<em>wĕhēmmâ lōʾ ʾĕlōhîm</em>) — the simple declaration. The surrounding nations&apos; confession (vv. 19-20) makes this statement ecumenically significant: even Gentiles will recognize the idols&apos; non-existence.</p>",
"21": "<p><strong>hinnĕnî môdîʿām bappaʿam hazzōʾt</strong> — &quot;I am going to make them know — this time I will make them know my hand and my strength&quot;; the double <em>yādaʿ</em> (know) — two different qal forms for knowing by experience. <em>Yādĕʿû ʾet-šĕmî YHWH</em> — they will know my name is YHWH. The formula &quot;that I am the LORD&quot; (the recognition formula) is the goal of the entire judgment sequence.</p>"
},
"17": {
"1": "<p><strong>ḥaṭṭāʾt Yĕhûdâ kĕtûbâ bĕʿēt barzel bĕṣippōren šāmîr</strong> — &quot;Judah&apos;s sin is written with an iron stylus; with a diamond tip it is engraved on the tablet of their heart&quot;; <em>lûaḥ libbām</em> (the tablet of their heart) directly anticipates the new covenant promise: Jer 31:33 promises the law written on the heart as blessing; here the sin is already written on the heart as curse. The MKT preserves the double inscription: on the heart (<em>lûaḥ libbām</em>) and on the horns of the altars (<em>qarnôt mizbĕḥôtêkem</em>).</p>",
"2": "<p><strong>kĕzĕkor bĕnêhem mizbĕḥôtām</strong> — &quot;even their children remember their altars and their Asherah poles&quot;; the intergenerational transmission of idolatry — the same cultural-transmission concern as 9:14. Children who remember the pagan cult sites means the practice is being taught as heritage, not abandoned as sin. &quot;Every spreading tree on every high hill&quot; — the stereotyped formula for hilltop-shrine Baal worship.</p>",
"3": "<p><strong>harî baśśādeh ḥêlĕkā kol-ʾôtsĕrôtêkā</strong> — &quot;O mountain in the open country, I will hand over your wealth and all your treasures as plunder&quot;; the &quot;mountain&quot; may refer to Jerusalem (Zion). The high shrines (<em>bāmôtêkā</em>) become the specific cause of the plunder: the cultic sites are both the site of sin and what triggers the punishment.</p>",
"4": "<p><strong>ûšāmaṭtā ûĕʾanāḥaltĕkā ʾăšer nātattî lāk</strong> — &quot;through your own actions you will forfeit the inheritance I gave you&quot;; <em>šāmaṭ</em> in the niphal means to release, let drop — the inheritance slips away through the people&apos;s own apostasy. &quot;I will make you serve your enemies in a land you do not know&quot; — the reversal from service of YHWH to service of enemies.</p>",
"5": "<p><strong>ʾārûr haggeber ʾăšer yibṭaḥ bāʾādām</strong> — &quot;Cursed is the one who puts his trust in human beings&quot;; the curse-formula (<em>ʾārûr</em>) matches the blessing-formula of v.7 (<em>bārûk</em>). <em>Bāṭaḥ bāʾādām</em> (trusts in humanity) vs. <em>bāṭaḥ baYHWH</em> (trusts in YHWH) — the same verb exposes the choice. The MKT&apos;s &quot;who turns his heart from the LORD&quot; follows MT: <em>wĕšāb libbô mēʾet YHWH</em>.</p>",
"6": "<p><strong>kĕʿarôʿêr bāʿărābâ</strong> — &quot;like a desert shrub&quot; (<em>ʿarôʿêr</em> = juniper/tamarisk in the desert); the cursed person&apos;s condition: dwelling in parched places (<em>ḥărērîm bammidbar</em>), unable to benefit from good when it comes. The contrast with v.8&apos;s tree-by-water will be stark. The MKT follows the tree/shrub imagery that connects directly to Psalm 1.</p>",
"7": "<p><strong>bārûk haggeber ʾăšer yibṭaḥ baYHWH</strong> — &quot;Blessed is the one who trusts in the LORD&quot;; the beatitude formula that mirrors Psalm 1:1-3 almost verbatim. The parallel structure (cursed/v.5-6 :: blessed/v.7-8) is the two-ways teaching at its most concentrated. <em>Ûhāyâ YHWH mibṭaḥô</em> — the LORD is his security (<em>mibṭāḥ</em> = place of trust/security).</p>",
"8": "<p><strong>kĕʿēts šātûl ʿal-mayim</strong> — &quot;like a tree planted beside a stream&quot;; the parallel with Psalm 1:3 is very close (<em>kĕʿēts šātûl ʿal-palgê mayim</em>). The tree&apos;s roots reach the water source (<em>ʿal-yûbal yĕšallaḥ šorāšāyw</em>). The phrase &quot;it does not fear when the heat comes&quot; (<em>wĕlōʾ yirʾeh kî-yābôʾ ḥōm</em>) — security through deep rootedness rather than superficial circumstances.</p>",
"9": "<p><strong>ʿāqōb hallēb mikkōl ûʾānûš hûʾ</strong> — &quot;The heart is more deceitful than anything else and is desperately sick&quot;; <em>ʿāqōb</em> (deceitful, treacherous) shares the root with Jacob&apos;s name (<em>yaʿăqōb</em>) — the heart that supplants and deceives. <em>ʾĀnûš</em> (incurable, desperately sick, weak) — the word used for incurable wounds (cf. 15:18). The rhetorical question <em>mî yēdāʿennû</em> (who can understand it?) is answered in v.10.</p>",
"10": "<p><strong>ʾănî YHWH ḥōqēr lēb bōḥēn kĕlāyôt</strong> — &quot;I, the LORD, examine the heart and test the inner mind (<em>kĕlāyôt</em>, kidneys/inner being)&quot;; YHWH as the only adequate diagnostician of the human heart. <em>Kĕlāyôt</em> (kidneys/reins) was considered the seat of the deepest inner life, emotions, and will in Hebrew anthropology. The MKT&apos;s &quot;inner mind&quot; represents an attempt to convey what &quot;kidneys&quot; meant to ancient Israelites. The purpose: to give everyone what their conduct deserves — the heart-examiner is the perfectly just rewarder.</p>",
"11": "<p><strong>kĕqōrēʾ dāgar wĕlōʾ yālād</strong> — &quot;like a partridge brooding over eggs she did not lay&quot;; the <em>qōrēʾ</em> partridge was believed to steal and incubate other birds&apos; eggs (the accuracy of this natural history is debated, but the proverb was current). The image: ill-gotten wealth is like stolen eggs — it hatches wealth that abandons its owner. The MKT preserves the proverb rather than explaining it away.</p>",
"12": "<p><strong>kissēʾ kābôd mārôm mĕrōšōn</strong> — &quot;A glorious throne, exalted from the beginning&quot; — a sudden praise-hymn for YHWH&apos;s heavenly throne. The juxtaposition with v.11 (the partridge who loses his wealth) and v.13 (those who forsake YHWH written in the dust) frames the throne-verse as a theological anchor: YHWH&apos;s throne is the fixed point against which all human pretension is measured.</p>",
"13": "<p><strong>YHWH miqweh Yiśrāʾēl</strong> — &quot;O LORD, the hope of Israel&quot;; the <em>miqweh</em>-title from 14:8 appears again — hope and water-reservoir. &quot;Those who turn from you will have their names written in the dust&quot; (<em>yikkātĕbû bāʾārets</em>) — the earth/dust as the anti-book: names written in dust versus names written in the book of life. The contrast: water-reservoir abandoned for broken cisterns leads to names written in dust rather than kept alive.</p>",
"14": "<p><strong>rĕpāʾênî YHWH wĕʾērāpēʾ</strong> — &quot;Heal me, O LORD, and I will truly be healed&quot;; the double-<em>rāpāʾ</em> (heal) construction — the source of healing and the healed state are both from YHWH. Similarly &quot;save me, and I will truly be saved&quot; (<em>hôšîʿēnî wĕʾiwwāšēʿâ</em>). The MKT&apos;s &quot;truly&quot; captures the emphasis that comes from the doubled verbal root: real/final healing depends entirely on YHWH&apos;s action.</p>",
"15": "<p><strong>ʾayyēh dĕbar-YHWH yābōʾ-nāʾ</strong> — &quot;Where is the word of the LORD? Let it come, if it is real!&quot; The taunt against Jeremiah: his prophecy of doom has not yet materialized. This is the standard challenge to the prophet: your announcement seems empty because the disaster has not arrived. The MKT&apos;s &quot;if it is real&quot; renders the skeptical <em>nāʾ</em> particle in context.</p>",
"16": "<p><strong>wĕʾănî lōʾ-ʾatsti mērōʿeh ʾaḥărêkā</strong> — &quot;But I have not run away from the calling of being your shepherd&quot;; <em>rōʿeh</em> (shepherd) here applied to Jeremiah as a pastor/shepherd figure following YHWH. He has not avoided (<em>ʾûts min-</em>) the painful calling. The MKT&apos;s &quot;the calling of being your shepherd&quot; is an interpretive rendering of the difficult phrase.</p>",
"17": "<p><strong>ʾal-tĕhî lî lĕmĕḥittâ</strong> — &quot;Do not be a source of dread to me&quot;; <em>mĕḥittâ</em> is terror, dread, dismay. Jeremiah asks that YHWH himself not become the source of his terror — a prayer that the divine presence remain as shelter (<em>maḥseh</em>) rather than threat. The MKT renders &quot;you are my shelter in the day of disaster&quot; following the positive formulation.</p>",
"18": "<p><strong>yēbōšû rōdĕpay wĕʾal-ʾēbōšâ ʾānî</strong> — &quot;Let those who persecute me be shamed — but not me&quot;; Jeremiah&apos;s imprecation against his persecutors. The threefold structure: shame/dismay/disaster — all the elements he fears for himself he asks YHWH to redirect onto his enemies. The MKT preserves the first-person singular throughout to maintain the intensity of the personal prayer.</p>",
"19": "<p><strong>šaʿar bĕnê-ʿām</strong> — &quot;the People&apos;s Gate&quot;; the location and the audience (<em>malkê Yĕhûdâ</em>, kings of Judah; <em>kol-Yĕhûdâ</em>, all Judah; <em>yōšĕbê Yĕrûšālaim</em>, inhabitants of Jerusalem) are given in full. The public proclamation at a major gate mirrors the temple sermon of ch. 7 in its public setting.</p>",
"20": "<p>Jeremiah is commissioned to call kings, Judah, and Jerusalem to hear the word of YHWH — the full public address formula. The inclusivity of the audience (kings to common people) emphasizes that the Sabbath command applies to all social levels equally.</p>",
"21": "<p><strong>šimĕrû napsôtêkem wĕʾal-tiśśĕʾû massāʾ bĕyôm haššabbāt</strong> — &quot;Take care for your own sakes and do not carry any load on the Sabbath day&quot;; <em>šāmar nepeš</em> (take care of yourself) implies the Sabbath prohibition is a matter of self-preservation, not merely legal compliance. The MKT&apos;s &quot;take care for your own sakes&quot; captures the reflexive force.</p>",
"22": "<p><strong>wĕlōʾ-tōṣîʾû massāʾ mibattêkem bĕyôm haššabbāt</strong> — &quot;Do not carry burdens out of your houses on the Sabbath day&quot;; the prohibition applies to outward commerce as well as inward carrying. &quot;Keep the Sabbath day holy as I commanded your ancestors&quot; (<em>wĕqiddaštĕm ʾet-yôm haššabbāt kaʾăšer ṣiwwîtî ʾet-ʾăbôtêkem</em>) — the ancestral command provides the authority for the current restatement.</p>",
"23": "<p><strong>wĕlōʾ šāmĕʿû wĕlōʾ hiṭṭû ʾet-ʾoznām</strong> — &quot;But they did not listen or pay attention&quot;; the standard refrain. <em>Wayyaqšû ʾet-ʿarpām</em> (stiffened their neck) — the <em>qāšeh ʿōrep</em> motif again (cf. 7:26). The pattern: instruction given → stiff-necked refusal → judgment. The historical precedent provides the context for the current conditional warnings.</p>",
"24": "<p>The positive conditional: <em>wĕhāyâ ʾim-šāmōaʿ tišmĕʿûn</em> — the emphatic conditional (&quot;if you truly listen to me&quot;; infinitive absolute). If Sabbath is kept, the Davidic throne is preserved. The conditional structure mirrors the temple sermon (7:3-7): the covenant&apos;s blessing depends on covenant-keeping. MKT preserves the &quot;truly&quot; construction.</p>",
"25": "<p><strong>ûbāʾû bĕšaʿărê hāʿîr hazzōʾt mĕlākim wĕśārîm</strong> — &quot;then kings and princes sitting on David&apos;s throne will enter through the gates&quot; — the restoration of the full Davidic political order is the positive consequence of Sabbath-keeping. The image of royal procession through the city gates (<em>rōkĕbîm bārékeb ûvassûsîm</em>) represents the full covenantal blessing in political form.</p>",
"26": "<p>The geographic breadth of those who will come — Benjamin, Shephelah, Negeb, and Jerusalem itself — and the range of offerings — burnt offerings (<em>ʿōlôt</em>), sacrifices (<em>zĕbāḥîm</em>), grain offerings (<em>minḥâ</em>), frankincense (<em>lĕbônâ</em>), thank offerings (<em>tôdâ</em>) — represent the full restored worship of the covenant community. The MKT&apos;s list follows MT precisely.</p>",
"27": "<p><strong>wĕʾim-lōʾ tišmĕʿû ʾēlay lĕqaddēš ʾet-yôm haššabbāt</strong> — &quot;But if you will not listen to me — if you refuse to keep the Sabbath day holy&quot;; the negative conditional completes the two-ways structure. The fire that will burn Jerusalem&apos;s fortresses (<em>wĕhiṣṣattî ʾēš bĕšĕʿārêhā</em>) is the covenant curse. The MKT preserves the literal &quot;fire into her gates&quot; as the image of total destruction — fire at the gates is the final judgment on the city.</p>"
}
}

def main():
    existing = load_comm('mkt-original', 'jeremiah')
    merge_comm(existing, JEREMIAH)
    save_comm('mkt-original', 'jeremiah', existing)
    print('Jeremiah 14-17 mkt-original written.')

if __name__ == '__main__':
    main()
